Returns a function that delays invoking `func` until `wait` milliseconds have passed since the last call (optional `immediate` runs on the leading edge).

```javascript
function debounce(func, wait = 100, immediate = false) {
  let timeout;
  return function(...args) {
    const context = this;
    const callNow = immediate && !timeout;
    clearTimeout(timeout);
    timeout = setTimeout(() => {
      timeout = null;
      if (!immediate) func.apply(context, args);
    }, wait);
    if (callNow) func.apply(context, args);
  };
}

// Example: log window width at most once every 200ms while resizing
const onResize = debounce(() => {
  console.log('Width:', window.innerWidth);
}, 200);

window.addEventListener('resize', onResize);
```
